import { createStore } from 'zustand/vanilla';
import { useStore } from 'zustand';

/**
 * Viewport state for canvas rendering.
 * Uses Zustand vanilla store for direct subscription without React re-renders.
 *
 * Coordinate system:
 * x_viewport = (t_unix - t_origin) * scale + offset
 */
export interface ViewportState {
  /** Pixels per millisecond */
  scale: number;
  /** Viewport offset in pixels (virtual scroll position) */
  offsetX: number;
  offsetY: number;
  /** Origin timestamp (start of timeline) */
  originTime: number;
  /** Viewport dimensions */
  width: number;
  height: number;
  /** Current Level of Detail (0=heatmap, 1=bars, 2=capsules) */
  lod: 0 | 1 | 2;
}

export interface ViewportActions {
  setScale: (scale: number) => void;
  setOffset: (x: number, y: number) => void;
  pan: (deltaX: number, deltaY: number) => void;
  zoom: (factor: number, centerX: number, centerY: number) => void;
  setDimensions: (width: number, height: number) => void;
  setLod: (lod: 0 | 1 | 2) => void;
}

const INITIAL_SCALE = 0.00001; // px/ms (approximately 36px per hour)
const MIN_SCALE = 0.0000001; // Very zoomed out (years visible)
const MAX_SCALE = 0.001; // Very zoomed in (seconds visible)

/** LOD thresholds with hysteresis (px per hour) */
const LOD_THRESHOLDS = {
  heatmapToBarEnter: 0.1,
  heatmapToBarExit: 0.15,
  barToCapsuleEnter: 20,
  barToCapsuleExit: 15,
} as const;

function calculateLod(scale: number, currentLod: 0 | 1 | 2): 0 | 1 | 2 {
  const pxPerHour = scale * 3600000; // ms per hour

  if (currentLod === 0) {
    if (pxPerHour > LOD_THRESHOLDS.heatmapToBarExit) return 1;
    return 0;
  }

  if (currentLod === 1) {
    if (pxPerHour < LOD_THRESHOLDS.heatmapToBarEnter) return 0;
    if (pxPerHour > LOD_THRESHOLDS.barToCapsuleEnter) return 2;
    return 1;
  }

  // currentLod === 2
  if (pxPerHour < LOD_THRESHOLDS.barToCapsuleExit) return 1;
  return 2;
}

export const viewportStore = createStore<ViewportState & ViewportActions>((set, get) => ({
  scale: INITIAL_SCALE,
  offsetX: 0,
  offsetY: 0,
  originTime: new Date('2024-01-01T00:00:00Z').getTime(),
  width: 0,
  height: 0,
  lod: 1,

  setScale: (scale: number) => {
    const clampedScale = Math.max(MIN_SCALE, Math.min(MAX_SCALE, scale));
    const currentLod = get().lod;
    set({
      scale: clampedScale,
      lod: calculateLod(clampedScale, currentLod),
    });
  },

  setOffset: (x: number, y: number) => {
    set({ offsetX: x, offsetY: y });
  },

  pan: (deltaX: number, deltaY: number) => {
    const { offsetX, offsetY } = get();
    set({ offsetX: offsetX + deltaX, offsetY: offsetY + deltaY });
  },

  zoom: (factor: number, centerX: number, _centerY: number) => {
    const { scale, offsetX } = get();
    const newScale = Math.max(MIN_SCALE, Math.min(MAX_SCALE, scale * factor));

    // Adjust offset to keep center point stationary
    const newOffsetX = centerX - (centerX - offsetX) * (newScale / scale);

    const currentLod = get().lod;
    set({
      scale: newScale,
      offsetX: newOffsetX,
      lod: calculateLod(newScale, currentLod),
    });
  },

  setDimensions: (width: number, height: number) => {
    set({ width, height });
  },

  setLod: (lod: 0 | 1 | 2) => {
    set({ lod });
  },
}));

/** React hook for viewport state (triggers re-render) */
export function useViewport<T>(selector: (state: ViewportState & ViewportActions) => T): T {
  return useStore(viewportStore, selector);
}

/** Direct access for non-React contexts (PixiJS render loop) */
export const getViewportState = viewportStore.getState;
export const subscribeViewport = viewportStore.subscribe;

import React, { useState, useEffect } from 'react';
import { 
  Train, Calendar, Wrench, BarChart3, Clock, AlertTriangle, CheckCircle, 
  ArrowRight, ArrowDown, Zap, Database, Cpu, Users, Settings, 
  TrendingUp, TrendingDown, Minus, Play, Pause, ChevronRight,
  Target, Layers, RefreshCw, FileText, Bell, HelpCircle, Book, Info, X
} from 'lucide-react';

// ============================================
// GLOSSARY DATA
// ============================================
const glossaryTerms = {
  'PM': {
    short: 'Preventive Maintenance',
    full: 'Manutenção Preventiva — Serviço programado realizado ANTES de uma falha ocorrer, baseado em intervalos de quilometragem ou tempo. Objetivo: prevenir quebras, não consertar depois.',
  },
  'PM50k': {
    short: 'Preventive Maintenance at 50,000 km',
    full: 'Manutenção preventiva realizada quando o trem atinge 50.000 km desde a última PM50k. Inclui: inspeção básica, troca de filtros, verificações de rotina. Duração típica: 1-2 dias.',
  },
  'PM100k': {
    short: 'Preventive Maintenance at 100,000 km',
    full: 'Manutenção preventiva realizada a cada 100.000 km. Mais completa que PM50k — inclui substituição de peças de desgaste, inspeção de componentes críticos. Duração típica: 3-5 dias.',
  },
  'PM150k': {
    short: 'Preventive Maintenance at 150,000 km',
    full: 'Manutenção preventiva realizada a cada 150.000 km. Revisão maior com foco em componentes críticos e sistemas de segurança. Duração típica: 5-7 dias.',
  },
  'Overhaul': {
    short: 'Major Overhaul / General Revision',
    full: 'Revisão geral completa do trem. Inclui recondicionamento extensivo, substituição de componentes maiores, pintura, etc. É a manutenção mais longa e cara. Duração típica: 10-15 dias.',
  },
  'RUC': {
    short: 'Recommended Usage Category',
    full: 'Categoria de Uso Recomendado — Classificação diária atribuída a cada trem indicando como ele deve ser utilizado (ACCELERATE, NOMINAL, ou DECELERATE) para manter a quilometragem alinhada ao Master Plan.',
  },
  'MIP': {
    short: 'Mixed-Integer Programming',
    full: 'Programação Inteira Mista — Técnica matemática de otimização que combina variáveis contínuas e inteiras (decisões sim/não). Usada por companhias aéreas, logística e manufatura para resolver problemas complexos de agendamento.',
  },
  'Drift': {
    short: 'Deviation from Plan',
    full: 'Desvio — Diferença entre a quilometragem REAL de um trem e sua quilometragem PLANEJADA em determinado momento. Drift positivo = trem à frente do plano. Drift negativo = trem atrasado.',
  },
  'Man-hours': {
    short: 'Unit of Labor',
    full: 'Horas-homem — Unidade de medida de trabalho. Se uma tarefa requer 100 man-hours, pode ser feita por 1 pessoa em 100 horas, ou 10 pessoas em 10 horas, etc.',
  },
  'Master Plan': {
    short: 'Optimized Long-term Schedule',
    full: 'Plano Mestre — Cronograma otimizado de TODAS as manutenções preventivas para toda a frota (128 trens) pelos próximos 12 anos. É o principal output da camada estratégica.',
  },
  'HiGHS': {
    short: 'High-performance Optimization Solver',
    full: 'Solver de otimização open-source de alto desempenho. Licença MIT, usado pelo Google internamente. Resolve problemas de programação linear e inteira mista.',
  },
  'Maximo': {
    short: 'IBM Maximo EAM System',
    full: 'IBM Maximo — Sistema de Enterprise Asset Management (EAM) usado pela Keolis MHI para gestão de ativos. Armazena dados de manutenção, inventário, ordens de serviço. Nossa integração importa/exporta dados do Maximo.',
  },
  'Workload Leveling': {
    short: 'Even Distribution of Work',
    full: 'Nivelamento de Carga — Técnica de distribuir trabalho uniformemente ao longo do tempo para evitar picos (sobrecarga) e vales (ociosidade). Reduz custos de hora extra e melhora previsibilidade.',
  },
  'Solver': {
    short: 'Optimization Algorithm',
    full: 'Software que encontra soluções para problemas matemáticos de otimização. Recebe variáveis, restrições e objetivo, e retorna a melhor solução possível (ou prova que não existe).',
  },
  'Constraint': {
    short: 'Rule/Limitation',
    full: 'Restrição — Regra que qualquer solução válida deve respeitar. Exemplos: "máximo 4 trens em manutenção por dia", "PM100k só pode ocorrer após PM50k".',
  },
  'Objective Function': {
    short: 'What to Optimize',
    full: 'Função Objetivo — Expressão matemática que queremos minimizar ou maximizar. No nosso caso: minimizar a variância (σ²) da carga de trabalho semanal.',
  },
};

// ============================================
// GLOSSARY TOOLTIP COMPONENT
// ============================================
const Term = ({ term, children }) => {
  const [showTooltip, setShowTooltip] = useState(false);
  const definition = glossaryTerms[term];

  if (!definition) {
    return <span className="font-semibold">{children || term}</span>;
  }

  return (
    <span className="relative inline-block">
      <span 
        className="font-semibold text-blue-600 border-b border-dashed border-blue-400 cursor-help"
        onMouseEnter={() => setShowTooltip(true)}
        onMouseLeave={() => setShowTooltip(false)}
      >
        {children || term}
      </span>
      {showTooltip && (
        <div className="absolute z-50 bottom-full left-1/2 transform -translate-x-1/2 mb-2 w-72 p-3 bg-gray-900 text-white text-sm rounded-lg shadow-xl">
          <p className="font-bold text-blue-300 mb-1">{term}: {definition.short}</p>
          <p className="text-gray-300 text-xs">{definition.full}</p>
          <div className="absolute top-full left-1/2 transform -translate-x-1/2 border-8 border-transparent border-t-gray-900" />
        </div>
      )}
    </span>
  );
};

// ============================================
// GLOSSARY PANEL COMPONENT
// ============================================
const GlossaryPanel = ({ isOpen, onClose }) => {
  if (!isOpen) return null;

  const categories = {
    'Maintenance Terms': ['PM', 'PM50k', 'PM100k', 'PM150k', 'Overhaul', 'Man-hours'],
    'System Concepts': ['RUC', 'Drift', 'Master Plan', 'Workload Leveling'],
    'Technical Terms': ['MIP', 'Solver', 'Constraint', 'Objective Function', 'HiGHS'],
    'External Systems': ['Maximo'],
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl shadow-2xl max-w-4xl w-full max-h-[80vh] overflow-hidden">
        <div className="bg-gradient-to-r from-blue-600 to-purple-600 text-white p-6 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Book className="w-8 h-8" />
            <div>
              <h2 className="text-2xl font-bold">Glossary of Terms</h2>
              <p className="text-blue-100">Glossário de Termos Técnicos</p>
            </div>
          </div>
          <button 
            onClick={onClose}
            className="p-2 hover:bg-white/20 rounded-lg transition-colors"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="p-6 overflow-y-auto max-h-[60vh]">
          {Object.entries(categories).map(([category, terms]) => (
            <div key={category} className="mb-6">
              <h3 className="text-lg font-bold text-gray-700 mb-3 border-b pb-2">{category}</h3>
              <div className="grid gap-3">
                {terms.map(term => {
