     1→import { Viewport } from 'pixi-viewport';
     2→import type { Application, Container, FederatedPointerEvent } from 'pixi.js';
     3→import { viewportStore } from '../engine/store/viewportStore';
     4→
     5→/**
     6→ * ViewportController - Integrates pixi-viewport for Google Maps style navigation.
     7→ *
     8→ * Features:
     9→ * - Pan with drag (touch and mouse)
    10→ * - Zoom with pinch and wheel
    11→ * - Inertia/deceleration physics
    12→ * - Clamp to world bounds
    13→ * - Sync with Zustand viewportStore
    14→ */
    15→
    16→export interface ViewportControllerConfig {
    17→  /** World width in pixels (total scrollable width) */
    18→  worldWidth: number;
    19→  /** World height in pixels (total scrollable height) */
    20→  worldHeight: number;
    21→  /** Enable inertia/deceleration */
    22→  decelerate: boolean;
    23→  /** Friction for deceleration (lower = more slide) */
    24→  friction: number;
    25→  /** Minimum scale (zoom out limit) */
    26→  minScale: number;
    27→  /** Maximum scale (zoom in limit) */
    28→  maxScale: number;
    29→  /** Enable clamping to world bounds */
    30→  clamp: boolean;
    31→}
    32→
    33→const DEFAULT_CONFIG: ViewportControllerConfig = {
    34→  worldWidth: 100000, // ~12 years at default scale
    35→  worldHeight: 10000, // ~250 rows at 40px each
    36→  decelerate: true,
    37→  friction: 0.95,
    38→  minScale: 0.01,
    39→  maxScale: 10,
    40→  clamp: false, // Allow free scrolling for now
    41→};
    42→
    43→export class ViewportController {
    44→  private viewport: Viewport | null = null;
    45→  private config: ViewportControllerConfig;
    46→  private isInitialized = false;
    47→  private lastScale = 1;
    48→  private syncToStoreEnabled = true;
    49→
    50→  constructor(config: Partial<ViewportControllerConfig> = {}) {
    51→    this.config = { ...DEFAULT_CONFIG, ...config };
    52→  }
    53→
    54→  /**
    55→   * Initialize the viewport with the PixiJS application.
    56→   */
    57→  init(app: Application): Viewport {
    58→    if (this.isInitialized && this.viewport) {
    59→      return this.viewport;
    60→    }
    61→
    62→    // Create pixi-viewport instance
    63→    this.viewport = new Viewport({
    64→      screenWidth: app.screen.width,
    65→      screenHeight: app.screen.height,
    66→      worldWidth: this.config.worldWidth,
    67→      worldHeight: this.config.worldHeight,
    68→      events: app.renderer.events,
    69→      passiveWheel: false,
    70→      stopPropagation: true,
    71→    });
    72→
    73→    // Configure interactions
    74→    this.viewport
    75→      .drag({ mouseButtons: 'left' })
    76→      .pinch()
    77→      .wheel({ smooth: 3, percent: 0.1 })
    78→      .clampZoom({
    79→        minScale: this.config.minScale,
    80→        maxScale: this.config.maxScale,
    81→      });
    82→
    83→    // Add deceleration for inertia
    84→    if (this.config.decelerate) {
    85→      this.viewport.decelerate({ friction: this.config.friction });
    86→    }
    87→
    88→    // Clamp to world bounds if enabled
    89→    if (this.config.clamp) {
    90→      this.viewport.clamp({
    91→        direction: 'all',
    92→        underflow: 'center',
    93→      });
    94→    }
    95→
    96→    // Subscribe to viewport events and sync with Zustand store
    97→    this.setupEventListeners();
    98→
    99→    // Initial sync from store
   100→    this.syncFromStore();
   101→
   102→    this.isInitialized = true;
   103→    this.lastScale = this.viewport.scale.x;
   104→
   105→    console.log('[ViewportController] Initialized with pixi-viewport');
   106→
   107→    return this.viewport;
   108→  }
   109→
   110→  /**
   111→   * Setup event listeners for viewport changes.
   112→   */
   113→  private setupEventListeners(): void {
   114→    if (!this.viewport) return;
   115→
   116→    // Sync on any viewport movement
   117→    this.viewport.on('moved', this.handleViewportMoved.bind(this));
   118→    this.viewport.on('zoomed', this.handleViewportZoomed.bind(this));
   119→    this.viewport.on('moved-end', this.handleViewportMovedEnd.bind(this));
   120→    this.viewport.on('zoomed-end', this.handleViewportZoomedEnd.bind(this));
   121→
   122→    // Handle pointer events for cursor change
   123→    this.viewport.on('pointerdown', this.handlePointerDown.bind(this));
   124→    this.viewport.on('pointerup', this.handlePointerUp.bind(this));
   125→  }
   126→
   127→  /**
   128→   * Handle viewport moved event.
   129→   */
   130→  private handleViewportMoved(): void {
   131→    if (!this.viewport || !this.syncToStoreEnabled) return;
   132→
   133→    // Update Zustand store with new position
   134→    const state = viewportStore.getState();
   135→
   136→    // Convert viewport position to offset (viewport uses top-left as origin)
   137→    const offsetX = -this.viewport.x;
   138→    const offsetY = -this.viewport.y;
   139→
   140→    if (offsetX !== state.offsetX || offsetY !== state.offsetY) {
   141→      state.setOffset(-this.viewport.x, -this.viewport.y);
   142→    }
   143→  }
   144→
   145→  /**
   146→   * Handle viewport zoomed event.
   147→   */
   148→  private handleViewportZoomed(): void {
   149→    if (!this.viewport || !this.syncToStoreEnabled) return;
   150→
   151→    const newScale = this.viewport.scale.x;
   152→
   153→    if (newScale !== this.lastScale) {
   154→      // Convert pixi-viewport scale to our scale system (px/ms)
   155→      // pixi-viewport scale is a multiplier, we need to convert
   156→      const baseScale = 0.00001; // Our base scale
   157→      const viewportScale = baseScale * newScale;
   158→
   159→      const state = viewportStore.getState();
   160→      state.setScale(viewportScale);
   161→
   162→      this.lastScale = newScale;
   163→    }
   164→
   165→    // Also update position since zoom changes it
   166→    this.handleViewportMoved();
   167→  }
   168→
   169→  /**
   170→   * Handle viewport moved end (after deceleration).
   171→   */
   172→  private handleViewportMovedEnd(): void {
   173→    this.handleViewportMoved();
   174→  }
   175→
   176→  /**
