import { Viewport } from 'pixi-viewport';
import type { Application, Container, FederatedPointerEvent } from 'pixi.js';
import { viewportStore } from '../engine/store/viewportStore';

/**
 * ViewportController - Integrates pixi-viewport for Google Maps style navigation.
 *
 * Features:
 * - Pan with drag (touch and mouse)
 * - Zoom with pinch and wheel
 * - Inertia/deceleration physics
 * - Clamp to world bounds
 * - Sync with Zustand viewportStore
 */

export interface ViewportControllerConfig {
  /** World width in pixels (total scrollable width) */
  worldWidth: number;
  /** World height in pixels (total scrollable height) */
  worldHeight: number;
  /** Enable inertia/deceleration */
  decelerate: boolean;
  /** Friction for deceleration (lower = more slide) */
  friction: number;
  /** Minimum scale (zoom out limit) */
  minScale: number;
  /** Maximum scale (zoom in limit) */
  maxScale: number;
  /** Enable clamping to world bounds */
  clamp: boolean;
}

const DEFAULT_CONFIG: ViewportControllerConfig = {
  worldWidth: 100000, // ~12 years at default scale
  worldHeight: 10000, // ~250 rows at 40px each
  decelerate: true,
  friction: 0.95,
  minScale: 0.01,
  maxScale: 10,
  clamp: false, // Allow free scrolling for now
};

export class ViewportController {
  private viewport: Viewport | null = null;
  private config: ViewportControllerConfig;
  private isInitialized = false;
  private lastScale = 1;
  private syncToStoreEnabled = true;

  constructor(config: Partial<ViewportControllerConfig> = {}) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  /**
   * Initialize the viewport with the PixiJS application.
   */
  init(app: Application): Viewport {
    if (this.isInitialized && this.viewport) {
      return this.viewport;
    }

    // Create pixi-viewport instance
    this.viewport = new Viewport({
      screenWidth: app.screen.width,
      screenHeight: app.screen.height,
      worldWidth: this.config.worldWidth,
      worldHeight: this.config.worldHeight,
      events: app.renderer.events,
      passiveWheel: false,
      stopPropagation: true,
    });

    // Configure interactions
    this.viewport
      .drag({ mouseButtons: 'left' })
      .pinch()
      .wheel({ smooth: 3, percent: 0.1 })
      .clampZoom({
        minScale: this.config.minScale,
        maxScale: this.config.maxScale,
      });

    // Add deceleration for inertia
    if (this.config.decelerate) {
      this.viewport.decelerate({ friction: this.config.friction });
    }

    // Clamp to world bounds if enabled
    if (this.config.clamp) {
      this.viewport.clamp({
        direction: 'all',
        underflow: 'center',
      });
    }

    // Subscribe to viewport events and sync with Zustand store
    this.setupEventListeners();

    // Initial sync from store
    this.syncFromStore();

    this.isInitialized = true;
    this.lastScale = this.viewport.scale.x;

    console.log('[ViewportController] Initialized with pixi-viewport');

    return this.viewport;
  }

  /**
   * Setup event listeners for viewport changes.
   */
  private setupEventListeners(): void {
    if (!this.viewport) return;

    // Sync on any viewport movement
    this.viewport.on('moved', this.handleViewportMoved.bind(this));
    this.viewport.on('zoomed', this.handleViewportZoomed.bind(this));
    this.viewport.on('moved-end', this.handleViewportMovedEnd.bind(this));
    this.viewport.on('zoomed-end', this.handleViewportZoomedEnd.bind(this));

    // Handle pointer events for cursor change
    this.viewport.on('pointerdown', this.handlePointerDown.bind(this));
    this.viewport.on('pointerup', this.handlePointerUp.bind(this));
  }

  /**
   * Handle viewport moved event.
   */
  private handleViewportMoved(): void {
    if (!this.viewport || !this.syncToStoreEnabled) return;

    // Update Zustand store with new position
    const state = viewportStore.getState();

    // Convert viewport position to offset (viewport uses top-left as origin)
    const offsetX = -this.viewport.x;
    const offsetY = -this.viewport.y;

    if (offsetX !== state.offsetX || offsetY !== state.offsetY) {
      state.setOffset(-this.viewport.x, -this.viewport.y);
    }
  }

  /**
   * Handle viewport zoomed event.
   */
  private handleViewportZoomed(): void {
    if (!this.viewport || !this.syncToStoreEnabled) return;

    const newScale = this.viewport.scale.x;

    if (newScale !== this.lastScale) {
      // Convert pixi-viewport scale to our scale system (px/ms)
      // pixi-viewport scale is a multiplier, we need to convert
      const baseScale = 0.00001; // Our base scale
      const viewportScale = baseScale * newScale;

      const state = viewportStore.getState();
      state.setScale(viewportScale);

      this.lastScale = newScale;
    }

    // Also update position since zoom changes it
    this.handleViewportMoved();
  }

  /**
   * Handle viewport moved end (after deceleration).
   */
  private handleViewportMovedEnd(): void {
    this.handleViewportMoved();
  }

  /**
   * Handle viewport zoomed end.
   */
  private handleViewportZoomedEnd(): void {
    this.handleViewportZoomed();
  }

  /**
   * Handle pointer down for cursor change.
   */
  private handlePointerDown(_event: FederatedPointerEvent): void {
    if (this.viewport?.parent) {
      const canvas = (this.viewport.parent as Container).parent;
      if (canvas && 'style' in canvas) {
        (canvas as unknown as HTMLElement).style.cursor = 'grabbing';
      }
    }
  }

  /**
   * Handle pointer up for cursor change.
   */
  private handlePointerUp(_event: FederatedPointerEvent): void {
    if (this.viewport?.parent) {
      const canvas = (this.viewport.parent as Container).parent;
      if (canvas && 'style' in canvas) {
        (canvas as unknown as HTMLElement).style.cursor = 'grab';
      }
    }
  }

  /**
   * Sync viewport from Zustand store (e.g., on programmatic navigation).
   */
  syncFromStore(): void {
    if (!this.viewport) return;

    const state = viewportStore.getState();

    // Temporarily disable sync to avoid feedback loop
    this.syncToStoreEnabled = false;

    // Convert store scale to viewport scale
    const baseScale = 0.00001;
    const viewportScale = state.scale / baseScale;

    this.viewport.scale.set(viewportScale);
    this.viewport.x = -state.offsetX;
    this.viewport.y = -state.offsetY;

    this.lastScale = viewportScale;

    this.syncToStoreEnabled = true;
  }

  /**
   * Animate to a specific position and scale.
   */
  animateTo(options: {
    x?: number;
    y?: number;
    scale?: number;
    time?: number;
  }): void {
    if (!this.viewport) return;

    const { x, y, scale, time = 500 } = options;

    if (scale !== undefined) {
      this.viewport.animate({
        scale: scale,
        position: x !== undefined && y !== undefined ? { x, y } : undefined,
        time,
        ease: 'easeOutQuad',
      });
    } else if (x !== undefined && y !== undefined) {
      this.viewport.animate({
        position: { x, y },
        time,
        ease: 'easeOutQuad',
      });
    }
  }

  /**
   * Fit viewport to show a specific rectangle.
   */
  fitToRect(x: number, y: number, width: number, height: number, padding = 50): void {
    if (!this.viewport) return;

    this.viewport.fit(true, width + padding * 2, height + padding * 2);
    this.viewport.moveCenter(x + width / 2, y + height / 2);
  }

  /**
   * Resize the viewport when screen size changes.
   */
  resize(screenWidth: number, screenHeight: number): void {
    if (!this.viewport) return;

    this.viewport.resize(screenWidth, screenHeight);
  }

  /**
   * Update world size (e.g., when data changes).
   */
  setWorldSize(width: number, height: number): void {
    if (!this.viewport) return;

    this.viewport.worldWidth = width;
    this.viewport.worldHeight = height;
  }

  /**
   * Get the pixi-viewport instance.
   */
  getViewport(): Viewport | null {
    return this.viewport;
  }

  /**
   * Check if controller is initialized.
   */
  isReady(): boolean {
    return this.isInitialized;
  }

  /**
   * Destroy the viewport controller.
   */
  destroy(): void {
    if (this.viewport) {
      this.viewport.removeAllListeners();
      this.viewport.destroy({ children: true });
      this.viewport = null;
    }
    this.isInitialized = false;
    console.log('[ViewportController] Destroyed');
  }
}
